311→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_TILING)
312→    const uint32_t col = ker_dim_y * ker_dim_x * in_tensor_ch;
313→    const uint32_t tiling_size = 256;
314→    long maxvl_per_loop;
315→
316→    //--- calculate the buffer address ---
317→    const long align_byte = 64;
318→    // buf_A
319→    int8_t *src1 = (int8_t*)in_tmp_buf;
320→    src1 = (int8_t*)nn_align((unsigned long)src1, align_byte);                  // align the starting addresss
321→    // buf_B: converted src2
322→    long src1_size = tiling_size * in_tensor_ch * ker_dim_x * ker_dim_y;
323→    int8_t *src2 = (int8_t*)(src1 + src1_size);
324→    src2 = (int8_t*)nn_align((unsigned long)src2, align_byte);                  // align the starting addresss
325→    // buf_C: temp buffer for int32_t tiling accumulator
326→    long src2_size = out_tensor_ch * in_tensor_ch * ker_dim_x * ker_dim_y;
327→    int32_t *dst_i32 = (int32_t*)(src2 + src2_size);
328→    dst_i32 = (int32_t*)nn_align((unsigned long)dst_i32, align_byte);           // align the starting addresss
329→    // buf_contri
330→    long dst_i32_size = tiling_size * out_tensor_ch;
331→    int32_t *contri_buf = (int32_t*)(dst_i32 + dst_i32_size);
332→    contri_buf = (int32_t*)nn_align((unsigned long)contri_buf, align_byte);     // align the starting addresss
333→
334→    // calculate the weight contribution
335→    const int8_t *pWt = ker_weight;
336→    int32_t *pContri_buf = contri_buf;
337→    const int32_t *pBias = bias;
338→    NDS_VEC_VSETVLI(maxvl_per_loop, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
339→    if (bias != NULL)
340→    {
341→        long out_tensor_ch2 = out_tensor_ch;
342→        long vl;
343→        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
344→        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum
345→
346→        while (out_tensor_ch2 > 0)
347→        {
348→            NDS_VEC_VSETVLI(vl, col, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
349→            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
350→            NDS_VEC_VSETVLI(vl, col, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
351→            NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);     // const one for vd4dot
352→
353→            long rhs_cols2 = col;
354→            while (rhs_cols2 >= maxvl_per_loop)
355→            {
356→                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
357→                NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
358→                pWt += vl;
359→                rhs_cols2 -= vl;
360→
361→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
362→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
363→            }
364→
365→            //clean one of the dot product source
366→            long tmp_avl;
367→            tmp_avl = rhs_cols2 + 3;
368→            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
369→            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
370→            NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
371→            NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot
372→
373→            // remain loop
374→            while (rhs_cols2 > 0)
375→            {
376→                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
377→                NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
378→                pWt += vl;
379→                rhs_cols2 -= vl;
380→
381→                vl = (vl + 3) >> 2;
382→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
383→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
384→            }
385→
386→            NDS_VEC_VSETVLI(vl, col, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
387→            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
388→
389→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
390→            NDS_VEC_VLE32_V(NDS_VEC_V1, pBias);
391→            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);     // add input_offset contribution
392→            NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V1);    // add bias
393→            NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
394→            pBias += vl;
395→            pContri_buf += vl;
396→            out_tensor_ch2--;
397→        }
398→    }
399→    else
400→    {
401→        long out_tensor_ch2 = out_tensor_ch;
402→        long vl;
403→        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
404→        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum
405→
406→        while (out_tensor_ch2 > 0)
407→        {
408→            NDS_VEC_VSETVLI(vl, col, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
409→            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
410→            NDS_VEC_VSETVLI(vl, col, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
411→            NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);     // const one for vd4dot
412→
413→            long rhs_cols2 = col;
414→            while (rhs_cols2 >= maxvl_per_loop)
415→            {
416→                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
417→                NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
418→                pWt += vl;
419→                rhs_cols2 -= vl;
420→
421→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
422→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
423→            }
424→
425→            //clean one of the dot product source
426→            long tmp_avl;
427→            tmp_avl = rhs_cols2 + 3;
428→            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
429→            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
430→            NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
431→            NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot
432→
433→            // remain loop
434→            while (rhs_cols2 > 0)
435→            {
436→                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
437→                NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
438→                pWt += vl;
439→                rhs_cols2 -= vl;
440→
441→                vl = (vl + 3) >> 2;
442→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
443→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
444→            }
445→
446→            NDS_VEC_VSETVLI(vl, col, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
447→            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
448→
449→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
450→            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);
451→            NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
452→            pContri_buf++;
453→            out_tensor_ch2--;
454→        }
455→    }
456→
457→    /* When out_tensor_ch is small, the tiling GEMM (vqmacc vectorizing across
458→     * out_tensor_ch) severely underutilizes vector width.  Switch to vd4dots
459→     * which vectorizes along the reduction dimension (col) instead — giving
460→     * up to 32x better vector utilization for small channel counts.
461→     * Uses 4-column batching with nn_mat_mult_kernel_s8_offset_unroll4 (4x4
462→     * tiled GEMM, LMUL=M1) for ~2x throughput vs the old 2-column v4 path. */
463→    if (out_tensor_ch <= 64)
464→    {
465→        /* Reuse src1 area as the 4-column im2col buffer (tiling buffer is
466→         * much larger than what 4-column batching needs). */
467→        int8_t *four_column_buf = src1;
468→
469→        for (long cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
470→        {
471→            int8_t *col_ptr = four_column_buf;
472→            int8_t *out = out_tensor;
473→
474→            for (long cur_out_y = 0; cur_out_y < out_tensor_dim_y; cur_out_y++)
475→            {
476→                const long ker_y_start = cur_out_y * stride_y - pad_y;
477→                const long ker_y_end = ker_y_start + ker_dim_y;
478→                for (long cur_out_x = 0; cur_out_x < out_tensor_dim_x; cur_out_x++)
479→                {
480→                    const long ker_x_start = cur_out_x * stride_x - pad_x;
481→                    const long ker_x_end = ker_x_start + ker_dim_x;
482→                    for (long cur_ker_y = ker_y_start; cur_ker_y < ker_y_end; cur_ker_y++)
483→                    {
484→                        for (long cur_ker_x = ker_x_start; cur_ker_x < ker_x_end; cur_ker_x++)
485→                        {
486→                            if (cur_ker_y < 0 || cur_ker_y >= in_tensor_dim_y || cur_ker_x < 0 || cur_ker_x >= in_tensor_dim_x)
487→                            {
488→                                nn_set_val_s8(col_ptr, -in_offset, in_tensor_ch);
489→                            }
490→                            else
491→                            {
492→                                nn_dup_s8(in_tensor + (cur_ker_y * in_tensor_dim_x + cur_ker_x) * in_tensor_ch, col_ptr, in_tensor_ch);
493→                            }
494→                            col_ptr += in_tensor_ch;
495→                        }
496→                    }
497→
498→                    /* Computation is filed for every 4 columns */
499→                    if (col_ptr == four_column_buf + 4 * col)
500→                    {
501→                        out = nn_mat_mult_kernel_s8_offset_unroll4(ker_weight,
502→                                                              four_column_buf,
503→                                                              out_tensor_ch,
504→                                                              out_shift,
505→                                                              out_scale,
506→                                                              in_offset,
507→                                                              out_offset,
508→                                                              act_min,
509→                                                              act_max,
510→                                                              col,
511→                                                              contri_buf,
512→                                                              out);
513→
514→                        /* counter reset */
515→                        col_ptr = four_column_buf;
516→                    }
517→                }
518→            }
519→
520→            /* Handle left-over pixels (1..3 remaining) */
521→            if (col_ptr != four_column_buf)
522→            {
523→                long leftover_bytes = col_ptr - four_column_buf;
524→
525→                /* Drain 2 pixels if we have 2 or 3 left over */
526→                if (leftover_bytes >= 2 * col)
527→                {
528→                    out = nn_mat_mult_kernel_s8_offset_v4(ker_weight,
529→                                                          four_column_buf,
530→                                                          out_tensor_ch,
531→                                                          out_shift,
532→                                                          out_scale,
533→                                                          in_offset,
534→                                                          out_offset,
535→                                                          act_min,
536→                                                          act_max,
537→                                                          col,
538→                                                          contri_buf,
539→                                                          out);
540→                    leftover_bytes -= 2 * col;
541→                }
542→
543→                /* Handle 1 remaining pixel with scalar path */
544→                if (leftover_bytes > 0)
545→                {
546→                    uint32_t vl;
547→                    const int8_t *pWt = ker_weight;
548→                    const int32_t *pOut_scale = out_scale;
549→                    const int32_t *pOut_shift = out_shift;
550→                    int32_t *pContri_buf2 = contri_buf;
551→                    const int8_t *pIn_base = col_ptr - col;
552→
553→                    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
554→                    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);
555→
556→                    for (long i = 0; i < out_tensor_ch; i++)
557→                    {
558→                        uint32_t rhs_cols2 = col;
559→                        const int8_t *pIn = pIn_base;
560→
561→                        NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
562→                        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
563→
564→                        while (rhs_cols2 >= maxvl_per_loop)
565→                        {
566→                            NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
567→                            NDS_VEC_VLE8_V(NDS_VEC_V8, pIn);
568→                            NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
569→                            rhs_cols2 -= vl;
570→                            pIn += vl;
571→                            pWt += vl;
572→
573→                            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
574→                            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
575→                        }
576→
577→                        if (rhs_cols2 > 0)
578→                        {
579→                            long tmp_avl = rhs_cols2 + 3;
580→                            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
581→                            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
582→
583→                            NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
584→                            NDS_VEC_VLE8_V(NDS_VEC_V8, pIn);
585→                            NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
586→                            pWt += vl;
587→
588→                            vl = (vl + 3) >> 2;
589→                            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
590→                            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
591→                        }
592→                        /* rhs_cols2 == 0: pWt already advanced past this channel in the loop above */
593→
594→                        NDS_VEC_VSETVLI(vl, col, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
595→                        NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
596→
597→                        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
598→                        NDS_VEC_VLE32_V(NDS_VEC_V4, pContri_buf2);
599→                        NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V4);
600→
601→                        NDS_VEC_VLE32_V(NDS_VEC_V2, pOut_shift);
602→                        NDS_VEC_VLE32_V(NDS_VEC_V3, pOut_scale);
603→                        NDS_VEC_VRSUB_VX(NDS_VEC_V2, NDS_VEC_V2, 30);
604→
605→                        NDS_VEC_VWMUL_VV(NDS_VEC_V4, NDS_VEC_V0, NDS_VEC_V3);
606→                        NDS_VEC_VNSRA_WV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V2);
607→                        NDS_VEC_VSSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 1);
608→
609→                        NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, out_offset);
610→                        NDS_VEC_VMAX_VX(NDS_VEC_V4, NDS_VEC_V4, act_min);
611→                        NDS_VEC_VMIN_VX(NDS_VEC_V4, NDS_VEC_V4, act_max);
612→
613→                        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
614→                        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
615→                        NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
616→                        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
617→                        NDS_VEC_VSE8_V(NDS_VEC_V4, out);
618→                        out += vl;
619→                        pOut_scale += vl;
620→                        pOut_shift += vl;
621→                        pContri_buf2 += vl;
622→                    }
623→                }
624→            }
625→
626→            in_tensor += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
627→            out_tensor += (out_tensor_dim_x * out_tensor_dim_y * out_tensor_ch);
628→        }
629→    }
630→    else
631→    {
632→    //transpose the kernel_weight for matrix multiplication
633→    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, out_tensor_ch, in_tensor_ch * ker_dim_x * ker_dim_y);
634→
635→    int8_t *out = out_tensor;
636→    for (long cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
637→    {
638→        int8_t *src1_buf = src1;
639→        int col_counter = 0;
640→
641→        /* This part implements the im256col function */
642→        for (long cur_out_y = 0; cur_out_y < out_tensor_dim_y; cur_out_y++)
643→        {
644→            for (long cur_out_x = 0; cur_out_x < out_tensor_dim_x; cur_out_x++)
645→            {
646→                for (long cur_ker_y = cur_out_y * stride_y - pad_y; cur_ker_y < cur_out_y * stride_y - pad_y + ker_dim_y; cur_ker_y++)
647→                {
648→                    for (long cur_ker_x = cur_out_x * stride_x - pad_x; cur_ker_x < cur_out_x * stride_x - pad_x + ker_dim_x; cur_ker_x++)
649→                    {
650→                        if (cur_ker_y < 0 || cur_ker_y >= in_tensor_dim_y || cur_ker_x < 0 || cur_ker_x >= in_tensor_dim_x)
651→                        {
652→                            nn_set_val_s8(src1_buf, -in_offset, in_tensor_ch);
653→                        }
654→                        else
655→                        {
656→                            nn_dup_s8(in_tensor + (cur_ker_y * in_tensor_dim_x + cur_ker_x) * in_tensor_ch, src1_buf, in_tensor_ch);
657→                        }
658→                        src1_buf += in_tensor_ch;
659→                    }
660→                }
661→                col_counter++;
662→
663→                /* Computation is filed for every 256 columns */
664→                if (col_counter == tiling_size)
665→                {
666→                    out = nn_mat_mul_kernel_tiling_asym_s8_s8_s8(src1,
667→                                                                 src2,
668→                                                                 dst_i32,
669→                                                                 out,
670→                                                                 out_scale,
671→                                                                 out_shift,
672→                                                                 col_counter,
673→                                                                 in_tensor_ch * ker_dim_x * ker_dim_y,
674→                                                                 out_tensor_ch,
675→                                                                 out_offset,
676→                                                                 act_min,
677→                                                                 act_max,
678→                                                                 contri_buf,
679→                                                                 tiling_size);
680→
681→                    /* counter reset */
682→                    col_counter = 0;
683→                    src1_buf = src1;
684→                }
685→            }
686→        }
687→
688→        /* check if there is left-over for compute */
689→        out = nn_mat_mul_kernel_tiling_asym_s8_s8_s8(src1,
690→                                                     src2,
691→                                                     dst_i32,
692→                                                     out,
693→                                                     out_scale,
694→                                                     out_shift,
695→                                                     col_counter,
696→                                                     in_tensor_ch * ker_dim_x * ker_dim_y,
697→                                                     out_tensor_ch,
698→                                                     out_offset,
699→                                                     act_min,
700→                                                     act_max,
701→                                                     contri_buf,
702→                                                     tiling_size);
703→        /* next in_tensor batch offset */
704→        in_tensor += (in_tensor_dim_x * in_tensor_dim_y * in_tensor_ch);
705→    }
706→    }
707→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_ELEN64)
708→    const uint32_t rhs_cols = ker_dim_y * ker_dim_x * in_tensor_ch;
709→    long maxvl_per_loop;
710→

