2300→int8_t* nn_mat_mult_kernel_s8_offset_v4(const int8_t *input_a,
2301→            const int8_t *input_b,
2302→            const int32_t out_tensor_ch,
2303→            const int32_t *out_shift,
2304→            const int32_t *out_scale,
2305→            const int32_t in_offset,    //value is in the range of [-127, 128]
2306→            const int32_t out_offset,   //value is in the range of [-128, 127]
2307→            const int32_t act_min,
2308→            const int32_t act_max,
2309→            const int32_t num_col_a,
2310→            const int32_t *contri_buf,
2311→            int8_t *out)
2312→{
2313→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
2314→    // 4x2 tiled vd4dots GEMM: 4 output channels x 2 pixels per tile, LMUL=M2
2315→    // Halves pixel data reloads compared to v2 (2x2 tile, LMUL=M4)
2316→    (void)in_offset;
2317→
2318→    /* set up the second output pointers */
2319→    int8_t *out_0 = out;
2320→    int8_t *out_1 = out_0 + out_tensor_ch;
2321→    const int8_t *ptr_a0 = input_a;
2322→    long vl;
2323→
2324→    long maxvl_per_loop;
2325→    NDS_VEC_VSETVLI(maxvl_per_loop, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
2326→
2327→    // Register allocation (LMUL=M2):
2328→    // Accumulators: v0(ch0*pix0), v2(ch0*pix1), v4(ch1*pix0), v6(ch1*pix1),
2329→    //               v8(ch2*pix0), v10(ch2*pix1), v12(ch3*pix0), v14(ch3*pix1)
2330→    // Load buffers: v16(pix0), v18(pix1), v20(wt0), v22(wt1), v24(wt2), v26(wt3)
2331→    // Scratch: v28-v31
2332→
2333→    for (long cur_row = 0; (cur_row + 4) <= out_tensor_ch; cur_row += 4)
2334→    {
2335→        /* setup pointers for B (im2col columns / pixels) */
2336→        const int8_t *ptr_b0 = input_b;
2337→        const int8_t *ptr_b1 = ptr_b0 + num_col_a;
2338→
2339→        /* setup pointers for A (weight rows / channels) */
2340→        const int8_t *ptr_a1 = ptr_a0 + num_col_a;
2341→        const int8_t *ptr_a2 = ptr_a1 + num_col_a;
2342→        const int8_t *ptr_a3 = ptr_a2 + num_col_a;
2343→
2344→        //init the 8 accumulators
2345→        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
2346→        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
2347→        NDS_VEC_VAND_VI(NDS_VEC_V2, NDS_VEC_V2, 0x0);
2348→        NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0x0);
2349→        NDS_VEC_VAND_VI(NDS_VEC_V6, NDS_VEC_V6, 0x0);
2350→        NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
2351→        NDS_VEC_VAND_VI(NDS_VEC_V10, NDS_VEC_V10, 0x0);
2352→        NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0x0);
2353→        NDS_VEC_VAND_VI(NDS_VEC_V14, NDS_VEC_V14, 0x0);
2354→
2355→        long col_count = num_col_a;
2356→        while(col_count >= maxvl_per_loop)
2357→        {
2358→            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
2359→            // Load 2 pixel columns (reused across all 4 weight rows)
2360→            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_b0);
2361→            NDS_VEC_VLE8_V(NDS_VEC_V18, ptr_b1);
2362→            // Load 4 weight rows
2363→            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_a0);
2364→            NDS_VEC_VLE8_V(NDS_VEC_V22, ptr_a1);
2365→            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_a2);
2366→            NDS_VEC_VLE8_V(NDS_VEC_V26, ptr_a3);
2367→            ptr_a0 += vl;
2368→            ptr_a1 += vl;
2369→            ptr_a2 += vl;
2370→            ptr_a3 += vl;
2371→            ptr_b0 += vl;
2372→            ptr_b1 += vl;
2373→            col_count -= vl;
2374→
2375→            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
2376→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0,  NDS_VEC_V20, NDS_VEC_V16);  //ch0*pix0
2377→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V2,  NDS_VEC_V20, NDS_VEC_V18);  //ch0*pix1
2378→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4,  NDS_VEC_V22, NDS_VEC_V16);  //ch1*pix0
2379→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V6,  NDS_VEC_V22, NDS_VEC_V18);  //ch1*pix1
2380→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8,  NDS_VEC_V24, NDS_VEC_V16);  //ch2*pix0
2381→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V24, NDS_VEC_V18);  //ch2*pix1
2382→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V26, NDS_VEC_V16);  //ch3*pix0
2383→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V26, NDS_VEC_V18);  //ch3*pix1
2384→        }
2385→
2386→        //extra process for the case of elements to be dot producted is not a mutiple of 4
2387→        if(col_count > 0)
2388→        {
2389→            //clean pixel buffers to avoid junk in tail affecting vd4dots
2390→            long tmp_avl;
2391→            tmp_avl = col_count + 3;
2392→            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
2393→            NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);
2394→            NDS_VEC_VAND_VI(NDS_VEC_V18, NDS_VEC_V18, 0);
2395→
2396→            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
2397→            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_b0);
2398→            NDS_VEC_VLE8_V(NDS_VEC_V18, ptr_b1);
2399→            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_a0);
2400→            NDS_VEC_VLE8_V(NDS_VEC_V22, ptr_a1);
2401→            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_a2);
2402→            NDS_VEC_VLE8_V(NDS_VEC_V26, ptr_a3);
2403→            ptr_a0 += vl;
2404→            ptr_a1 += vl;
2405→            ptr_a2 += vl;
2406→            ptr_a3 += vl;
2407→
2408→            vl = (vl + 3) >> 2;
2409→            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
2410→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0,  NDS_VEC_V20, NDS_VEC_V16);
2411→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V2,  NDS_VEC_V20, NDS_VEC_V18);
2412→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4,  NDS_VEC_V22, NDS_VEC_V16);
2413→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V6,  NDS_VEC_V22, NDS_VEC_V18);
2414→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8,  NDS_VEC_V24, NDS_VEC_V16);
2415→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V24, NDS_VEC_V18);
2416→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V26, NDS_VEC_V16);
2417→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V26, NDS_VEC_V18);
2418→        }
2419→
2420→        // === Reduction epilogue: 8 vredsum → pack to VL=4 → requantize ===
2421→        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
2422→        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);
2423→        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
2424→
2425→        // Reduce 8 accumulators to scalars in element [0]
2426→        NDS_VEC_VREDSUM_VS(NDS_VEC_V16, NDS_VEC_V0,  NDS_VEC_V31);  //ch0*pix0 → v16[0]
2427→        NDS_VEC_VREDSUM_VS(NDS_VEC_V17, NDS_VEC_V4,  NDS_VEC_V31);  //ch1*pix0 → v17[0]
2428→        NDS_VEC_VREDSUM_VS(NDS_VEC_V18, NDS_VEC_V8,  NDS_VEC_V31);  //ch2*pix0 → v18[0]
2429→        NDS_VEC_VREDSUM_VS(NDS_VEC_V19, NDS_VEC_V12, NDS_VEC_V31);  //ch3*pix0 → v19[0]
2430→        NDS_VEC_VREDSUM_VS(NDS_VEC_V20, NDS_VEC_V2,  NDS_VEC_V31);  //ch0*pix1 → v20[0]
2431→        NDS_VEC_VREDSUM_VS(NDS_VEC_V21, NDS_VEC_V6,  NDS_VEC_V31);  //ch1*pix1 → v21[0]
2432→        NDS_VEC_VREDSUM_VS(NDS_VEC_V22, NDS_VEC_V10, NDS_VEC_V31);  //ch2*pix1 → v22[0]
2433→        NDS_VEC_VREDSUM_VS(NDS_VEC_V23, NDS_VEC_V14, NDS_VEC_V31);  //ch3*pix1 → v23[0]
2434→
2435→        // Pack 4 scalars into VL=4 vectors via vslideup
2436→        // pix0: v16 = [ch0, ch1, ch2, ch3]
2437→        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
2438→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V17, 1);
2439→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V21, 1);
2440→        NDS_VEC_VSETVLI(vl, 3, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
2441→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V18, 2);
2442→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V22, 2);
2443→        NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
2444→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V19, 3);
2445→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V23, 3);
2446→
2447→        // v16 = pix0 [ch0,ch1,ch2,ch3], v20 = pix1 [ch0,ch1,ch2,ch3]
2448→
2449→        //add extra contribution back
2450→        NDS_VEC_VLE32_V(NDS_VEC_V24, contri_buf);
2451→        contri_buf += vl;
2452→        NDS_VEC_VADD_VV(NDS_VEC_V16, NDS_VEC_V16, NDS_VEC_V24);
2453→        NDS_VEC_VADD_VV(NDS_VEC_V20, NDS_VEC_V20, NDS_VEC_V24);
2454→
2455→        //===== Quantize down =====
2456→        NDS_VEC_VLE32_V(NDS_VEC_V2, out_shift);
2457→        NDS_VEC_VLE32_V(NDS_VEC_V3, out_scale);
2458→        NDS_VEC_VRSUB_VX(NDS_VEC_V2, NDS_VEC_V2, 30);
2459→
2460→        NDS_VEC_VWMUL_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V3);
2461→        NDS_VEC_VWMUL_VV(NDS_VEC_V6, NDS_VEC_V20, NDS_VEC_V3);
2462→        NDS_VEC_VNSRA_WV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V2);
2463→        NDS_VEC_VNSRA_WV(NDS_VEC_V6, NDS_VEC_V6, NDS_VEC_V2);
2464→        NDS_VEC_VSSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 1);
2465→        NDS_VEC_VSSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 1);
2466→
2467→        // Add offset
2468→        NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, out_offset);
2469→        NDS_VEC_VADD_VX(NDS_VEC_V6, NDS_VEC_V6, out_offset);
