2473→        NDS_VEC_VMIN_VX(NDS_VEC_V4, NDS_VEC_V4, act_max);
2474→        NDS_VEC_VMAX_VX(NDS_VEC_V6, NDS_VEC_V6, act_min);
2475→        NDS_VEC_VMIN_VX(NDS_VEC_V6, NDS_VEC_V6, act_max);
2476→
2477→        //narrowing and store the results
2478→        NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
2479→        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
2480→        NDS_VEC_VNSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 0);
2481→        NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
2482→        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
2483→        NDS_VEC_VNSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 0);
2484→        NDS_VEC_VSE8_V(NDS_VEC_V4, out_0);
2485→        NDS_VEC_VSE8_V(NDS_VEC_V6, out_1);
2486→        out_0 += 4;
2487→        out_1 += 4;
2488→        out_scale += 4;
2489→        out_shift += 4;
2490→
2491→        ptr_a0 += 3 * (long)num_col_a;  // skip past channels 1,2,3
2492→    }
